import React, { useEffect, useState } from 'react';
import { useSearchParams, useNavigate, Link } from 'react-router-dom';
import { paymentAPI } from '../utils/api';

const PaymentSuccess = () => {
  const [searchParams] = useSearchParams();
  const navigate = useNavigate();
  const [status, setStatus] = useState('processing');
  const [message, setMessage] = useState('Processing your payment...');

  useEffect(() => {
    const paymentId = searchParams.get('paymentId');
    const payerId = searchParams.get('PayerID');
    const mock = searchParams.get('mock');

    if (mock === 'true') {
      setStatus('success');
      setMessage('Payment completed successfully!');
      return;
    }

    if (paymentId && payerId) {
      executePayment(paymentId, payerId);
    } else {
      setStatus('error');
      setMessage('Missing payment information.');
    }
  }, []);

  const executePayment = async (paymentId, payerId) => {
    try {
      await paymentAPI.executePayment({ paymentId, payerId });
      setStatus('success');
      setMessage('Payment completed successfully! Your appointment is confirmed.');
    } catch (error) {
      setStatus('error');
      setMessage(error.response?.data?.message || 'Payment execution failed.');
    }
  };

  return (
    <div className="container">
      <div style={{ maxWidth: '500px', margin: '80px auto', textAlign: 'center' }}>
        <div className="card">
          {status === 'processing' && (
            <>
              <div className="loading" style={{ position: 'static', height: 'auto', marginBottom: '20px' }}>
                <div className="spinner"></div>
              </div>
              <h2>Processing Payment...</h2>
              <p style={{ color: '#666' }}>Please wait while we confirm your payment.</p>
            </>
          )}

          {status === 'success' && (
            <>
              <div style={{ fontSize: '4rem', marginBottom: '20px' }}>✅</div>
              <h2 style={{ color: '#28a745', marginBottom: '10px' }}>Payment Successful!</h2>
              <p style={{ color: '#666', marginBottom: '30px' }}>{message}</p>
              <Link to="/patient/appointments">
                <button className="btn btn-primary">View My Appointments</button>
              </Link>
            </>
          )}

          {status === 'error' && (
            <>
              <div style={{ fontSize: '4rem', marginBottom: '20px' }}>❌</div>
              <h2 style={{ color: '#dc3545', marginBottom: '10px' }}>Payment Failed</h2>
              <p style={{ color: '#666', marginBottom: '30px' }}>{message}</p>
              <Link to="/patient/search-doctors">
                <button className="btn btn-primary">Try Again</button>
              </Link>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default PaymentSuccess;
